import{d,c as s,o as p,j as e,a$ as _,_ as o,G as c}from"./chunks/framework.Bf-WjO2H.js";const i={class:"letter-page"},v=d({__name:"LetterView2026",setup(r){function a(){window.location.href="/anniversary/2026"}return(n,t)=>(p(),s("div",i,[e("div",{class:"letter-card"},[t[0]||(t[0]=_('<h1 class="letter-title" data-v-58d5259a>致茶友们的一封信</h1><div class="letter-body" data-v-58d5259a><p class="greeting" data-v-58d5259a>各位亲爱的茶友：</p><p data-v-58d5259a>2021 年 4 月 15 日，在复旦园和煦的春风中，一只旦挞猫猫悄悄在校园的某个角落里破壳而出，并用代码为复旦大学的各位茶友搭建起一个小小的交流空间。转眼间，在各位茶友的陪伴下，这只可爱的猫猫迎来了五岁生日。</p><p data-v-58d5259a>五年来，猫猫迎来了五万余位作客的茶友；人声鼎沸中，五百余万条消息在茶楼里留下回响。对于每一位造访的茶友来说，茶楼或许都有着属于自己的独特意义。</p><p data-v-58d5259a>或许，你是茶楼的常客，每天造访已经成为习惯；或许，你心血来潮时会来听听最新校园奇谭。</p><p data-v-58d5259a>或许，你最爱翻阅猫猫钦点的「#旦挞精选」；或许，你最关心的是茶楼顶上的公告栏。</p><p data-v-58d5259a>或许，你热爱在茶楼激扬文字，是名副其实的「大水怪」；或许，你在默默潜水时注视着浪花有所感慨。</p><p data-v-58d5259a>或许，茶楼是你茶余饭后的快乐来源；或许，茶楼是你深夜 emo 时的温暖港湾。</p><p data-v-58d5259a>或许，茶楼是你分享生活智慧的闪耀平台；或许，茶楼是你手足无措时的智囊团。</p><p data-v-58d5259a>或许，茶楼是你碰撞思维火花的试炼场；或许，茶楼是你寻找同好的朋友圈。</p><p data-v-58d5259a>无论茶楼对大家来说意味着什么，旦挞猫猫都会感到非常欣慰！猫猫喜欢看到茶楼里热闹的样子，喜欢身边有熟客的陪伴，喜欢重逢阔别已久的面孔，也喜欢看到大家脸上的笑容！每当看到温馨和谐的茶楼，猫猫都会忍不住幸福地发眯起眼睛，发出咕噜咕噜的声音！（当然，猫猫最喜欢的是遵守规则、维护茶楼友好氛围的好孩子，对于不遵守规则的坏孩子猫猫也是不会客气的！）</p><p data-v-58d5259a>茶楼的今天离不开各位茶友的踊跃参与，也离不开各位猫猫的饲养员——旦挞团队的辛勤付出。如今，旦挞团队已经有了 70 位成员。对于旦挞团队的各位成员来说，为各位茶友提供更好的服务是我们一直以来的追求。我们喜欢看到大家在 GitHub 仓库中点亮的星星，喜欢看到维护时大家表达的支持和鼓励；喜欢看到大家对猫猫表情包、红包封面、文创物料、推送文案的夸夸和热情，喜欢看到各个社团的联动申请；喜欢看到大家对卖萌的管理员表达的善意，也喜欢看到大家在站务区、QQ 群和邮件里对团队工作提出的真诚建议。如果你也希望成为一名饲养员，那么我们非常欢迎你的加入！</p><p data-v-58d5259a>感谢各位茶友一直以来的支持，希望大家都能够常来坐坐，在茶楼收获更多快乐～猫猫会一直在茶楼里摇着尾巴等待你！</p><div class="signature" data-v-58d5259a><p data-v-58d5259a>旦挞团队</p><p data-v-58d5259a>旦挞猫猫（爪印代）</p><p data-v-58d5259a>2026 年 4 月 15 日</p></div></div>',2)),e("button",{class:"back-btn",onClick:a},"返回五周年庆")])]))}}),l=o(v,[["__scopeId","data-v-58d5259a"]]),f=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"page","sidebar":false},"headers":[],"relativePath":"anniversary/2026/letter.md","filePath":"anniversary/2026/letter.md"}'),u={name:"anniversary/2026/letter.md"},g=d({...u,setup(r){return(a,n)=>(p(),s("div",null,[c(l)]))}});export{f as __pageData,g as default};
